import{c as e,Q as t,j as r,m as n}from"./chunks/framework.DpF7k2f3.js";const m=JSON.parse('{"title":"第6章 RAG検索拡張生成","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ja/part2-fundamentals/chapter6.md","filePath":"ja/part2-fundamentals/chapter6.md"}'),l={name:"ja/part2-fundamentals/chapter6.md"};function i(p,a,o,d,s,c){return t(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="第6章-rag検索拡張生成" tabindex="-1">第6章 RAG検索拡張生成 <a class="header-anchor" href="#第6章-rag検索拡張生成" aria-label="Permalink to &quot;第6章 RAG検索拡張生成&quot;">​</a></h1><h2 id="本章で学べること" tabindex="-1">本章で学べること <a class="header-anchor" href="#本章で学べること" aria-label="Permalink to &quot;本章で学べること&quot;">​</a></h2><p>第5章が「怎么让大模型听你的话」を教えたなら、この章は「怎么让大模型知道它原本不知道的事」を教えます。</p><p>RAG（Retrieval-Augmented Generation、检索增强生成）はAIアプリ開発で最もコアな技術の一つです。面试的时候80%会问到RAG；做项目的时候十个里有九个需要RAG。理由は简单：模型がどれだけ強くても知识の境界线がある——会社の内部ドキュメント、業務フロー、最新製品データなどを知らない。RAGは这些问题を解決するものです。</p><p>しかし、多くの学生はRAGの表面だけを学びました——ベクトル検索知道、文档随便切切、参数随便调调就觉得OK了。面试官深入问一下就会露馅：リランキング怎么做的？このシナリオでなぜセマンティックチャンク而不是递归チャンクを使うのか？Self-RAGとCRAGの違い是什么？マルチモーダルドキュメント怎么处理？</p><p>读完这章你会带走：</p><ul><li>RAGの本质を深く理解：不只是「检索+生成」，而是一套解决知识边界问题的系统工程</li><li>テキストチャンクのN种策略をマスター：递归、语义、Parent-Child、そして什么时候用什么</li><li>Embeddingモデルの 선택：2026年中文Embedding哪家强，怎么微调，什么时候需要微调</li><li>检索戦略を攻略：ハイブリッド検索、リランキング、クエリ書き換え、適応型检索</li></ul><hr><blockquote><p><strong>全文の翻訳は後日公開予定、しばらくお待ちください。中文版は今すぐ読めます。</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part2-fundamentals/chapter6.html">中文版阅读</a></p></blockquote>',9)])])}const u=e(l,[["render",i]]);export{m as __pageData,u as default};
